select
id, resources_ip, node_port, public_key, short_id, user_id, sni
from resource_allocation_temporary_storage

    1 = 1 and is_deleted = 0

        and id = #{id}


        and resources_ip = #{resourcesIp}


        and node_port = #{nodePort}


        and public_key = #{publicKey}


        and short_id = #{shortId}


        and user_id = #{userId}


        and sni = #{sni}

